import React, { useMemo, useState } from "react";

const DUMMY_SYSTEMS = [
  {
    id: "sys-1001",
    owner: "Manufacturing / Line A",
    healthScore: 92,
    status: "healthy",
    primaryRootCause: "Hardware",
    confidence: 96,
    lastSeen: new Date(Date.now() - 3 * 60 * 1000).toISOString(),
  },
  {
    id: "sys-1002",
    owner: "Data Center / Rack 7",
    healthScore: 64,
    status: "warning",
    primaryRootCause: "Software",
    confidence: 81,
    lastSeen: new Date(Date.now() - 22 * 60 * 1000).toISOString(),
  },
  {
    id: "sys-1003",
    owner: "Field Device / Pump 4",
    healthScore: 38,
    status: "critical",
    primaryRootCause: "Security",
    confidence: 92,
    lastSeen: new Date(Date.now() - 5 * 60 * 60 * 1000).toISOString(),
  },
];

function relativeTimeFrom(dateIsoString) {
  const then = new Date(dateIsoString).getTime();
  const now = Date.now();
  const d = Math.abs(now - then) / 1000;

  if (d < 60) return `${Math.floor(d)} sec ago`;
  if (d < 3600) return `${Math.floor(d / 60)} min ago`;
  if (d < 86400) return `${Math.floor(d / 3600)} hr ago`;
  return `${Math.floor(d / 86400)} day ago`;
}

function statusBadge(status) {
  switch (status) {
    case "healthy":
      return "bg-green-100 text-green-700";
    case "warning":
      return "bg-yellow-100 text-yellow-700";
    case "critical":
      return "bg-red-100 text-red-700";
    default:
      return "bg-gray-100 text-gray-700";
  }
}

export default function SystemsOverview({ openSystem }) {
  const [statusFilter, setStatusFilter] = useState("All");

  const filtered = useMemo(() => {
    return DUMMY_SYSTEMS.filter((s) => {
      if (statusFilter !== "All" && s.status !== statusFilter.toLowerCase())
        return false;
      return true;
    });
  }, [statusFilter]);

  return (
    <div className="space-y-6">

      {/* HEADER */}
      <div className="flex flex-col md:flex-row md:justify-between gap-4">
        <div>
          <h1 className="text-2xl font-semibold">Systems Overview</h1>
          <p className="text-sm text-gray-500">
            AI evaluated system health across all devices
          </p>
        </div>

        <select
          value={statusFilter}
          onChange={(e) => setStatusFilter(e.target.value)}
          className="border px-3 py-2 rounded-md"
        >
          <option>All</option>
          <option>Healthy</option>
          <option>Warning</option>
          <option>Critical</option>
        </select>
      </div>

      {/* TABLE */}
      <div className="bg-white border rounded-xl overflow-x-auto">

        <table className="min-w-full">

          <thead className="bg-gray-50 text-xs uppercase text-gray-600">
            <tr>
              <th className="px-5 py-3 text-left">System</th>
              <th className="px-5 py-3 text-left">Owner</th>
              <th className="px-5 py-3 text-left">Health</th>
              <th className="px-5 py-3 text-left">Root Cause</th>
              <th className="px-5 py-3 text-left">Confidence</th>
              <th className="px-5 py-3 text-left">Last Seen</th>
              <th className="px-5 py-3 text-left">Actions</th>
            </tr>
          </thead>

          <tbody>

            {filtered.map((s) => (

              <tr key={s.id} className="border-t hover:bg-gray-50">

                <td className="px-5 py-4 font-medium text-blue-600">
                  {s.id}
                </td>

                <td className="px-5 py-4">{s.owner}</td>

                <td className="px-5 py-4">
                  <span
                    className={`px-3 py-1 rounded-full text-xs font-medium ${statusBadge(
                      s.status
                    )}`}
                  >
                    {s.healthScore} • {s.status}
                  </span>
                </td>

                <td className="px-5 py-4">{s.primaryRootCause}</td>

                <td className="px-5 py-4">{s.confidence}%</td>

                <td className="px-5 py-4 text-sm text-gray-500">
                  {relativeTimeFrom(s.lastSeen)}
                </td>

                <td className="px-5 py-4 flex gap-2">

                  <button
                    onClick={() => openSystem(s)}
                    className="px-3 py-1.5 border rounded-md text-sm hover:bg-gray-100"
                  >
                    Details
                  </button>

                  <button className="px-3 py-1.5 bg-blue-600 text-white rounded-md text-sm hover:bg-blue-700">
                    Assign
                  </button>

                </td>

              </tr>

            ))}

          </tbody>
        </table>

      </div>
    </div>
  );
}
